// Searchable Dropdown Component
const SearchableDropdown = ({ label, value, options, onChange, placeholder, disabled, error, icon }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [search, setSearch] = useState('');
  const dropdownRef = useRef(null);
  const inputRef = useRef(null);

  const filtered = options.filter(opt =>
    opt.toLowerCase().includes(search.toLowerCase())
  );

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setIsOpen(false);
        setSearch('');
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    if (isOpen && inputRef.current) inputRef.current.focus();
  }, [isOpen]);

  const handleSelect = (opt) => {
    onChange(opt);
    setIsOpen(false);
    setSearch('');
  };

  return (
    <div className="mb-0" ref={dropdownRef}>
      <label className="block text-sm font-medium text-gray-700 mb-2">{label}</label>
      <div className="relative">
        {/* Trigger Button */}
        <button
          type="button"
          disabled={disabled}
          onClick={() => { if (!disabled) setIsOpen(!isOpen); }}
          className={`w-full px-4 py-3 border rounded-lg text-left flex items-center justify-between transition-all
            ${disabled ? 'bg-gray-100 text-gray-400 cursor-not-allowed border-gray-200' : 'bg-white border-gray-300 hover:border-blue-400 cursor-pointer'}
            ${isOpen ? 'border-blue-500 ring-2 ring-blue-100' : ''}
            ${error ? 'border-red-400' : ''}
          `}
        >
          <span className={value ? 'text-gray-900' : 'text-gray-400'}>
            {value || placeholder}
          </span>
          <ChevronDown
            size={18}
            className={`text-gray-400 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`}
          />
        </button>

        {/* Dropdown Panel */}
        {isOpen && (
          <div className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-xl shadow-xl overflow-hidden">
            {/* Search Input */}
            <div className="px-3 pt-3 pb-2 border-b border-gray-100">
              <div className="flex items-center gap-2 px-3 py-2 bg-gray-50 rounded-lg">
                <Search size={14} className="text-gray-400 shrink-0" />
                <input
                  ref={inputRef}
                  type="text"
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  placeholder={`Search ${label.toLowerCase()}...`}
                  className="w-full bg-transparent text-sm outline-none text-gray-700 placeholder-gray-400"
                />
              </div>
            </div>

            {/* Options List */}
            <div className="max-h-52 overflow-y-auto">
              {filtered.length === 0 ? (
                <div className="px-4 py-3 text-sm text-gray-400 text-center">No results found</div>
              ) : (
                filtered.map((opt) => (
                  <button
                    key={opt}
                    type="button"
                    onClick={() => handleSelect(opt)}
                    className={`w-full text-left px-4 py-2.5 text-sm transition-colors hover:bg-blue-50 hover:text-blue-700
                      ${opt === value ? 'bg-blue-50 text-blue-600 font-medium' : 'text-gray-700'}
                    `}
                  >
                    {opt}
                  </button>
                ))
              )}
            </div>
          </div>
        )}
      </div>
      {error && <p className="text-red-500 text-sm mt-1">{error}</p>}
    </div>
  );
};

// Main LocationSelector component
const LocationSelector = ({ formData, setFormData, errors, setErrors }) => {
  const states = Object.keys(INDIA_LOCATIONS).sort();
  const cities = formData.state ? Object.keys(INDIA_LOCATIONS[formData.state]).sort() : [];
  const pinCodes = (formData.state && formData.city && INDIA_LOCATIONS[formData.state][formData.city])
    ? INDIA_LOCATIONS[formData.state][formData.city]
    : [];

  const handleStateChange = (state) => {
    setFormData(prev => ({ ...prev, state, city: '', pinCode: '' }));
    setErrors(prev => ({ ...prev, state: '', city: '', pinCode: '' }));
  };

  const handleCityChange = (city) => {
    setFormData(prev => ({ ...prev, city, pinCode: '' }));
    setErrors(prev => ({ ...prev, city: '', pinCode: '' }));
  };

  const handlePinChange = (pin) => {
    setFormData(prev => ({ ...prev, pinCode: pin }));
    setErrors(prev => ({ ...prev, pinCode: '' }));
  };

  const handleAreaChange = (e) => {
    setFormData(prev => ({ ...prev, area: e.target.value }));
    if (errors.area) setErrors(prev => ({ ...prev, area: '' }));
  };

  return (
    <div className="mb-6">
      <label className="block text-sm font-medium text-gray-700 mb-2">
        <span className="flex items-center gap-1.5">
          <MapPin size={14} className="text-blue-500" />
          Address
        </span>
      </label>

      {/* Area (free text) */}
      <div className="mb-3">
        <input
          type="text"
          name="area"
          value={formData.area}
          onChange={handleAreaChange}
          className={`w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent
            ${errors.area ? 'border-red-400' : 'border-gray-300'}`}
          placeholder="Area / Street / Locality"
        />
        {errors.area && <p className="text-red-500 text-sm mt-1">{errors.area}</p>}
      </div>

      {/* State */}
      <div className="mb-3">
        <SearchableDropdown
          label="State"
          value={formData.state}
          options={states}
          onChange={handleStateChange}
          placeholder="Select your state"
          error={errors.state}
        />
      </div>

      {/* City */}
      <div className="mb-3">
        <SearchableDropdown
          label="City"
          value={formData.city}
          options={cities}
          onChange={handleCityChange}
          placeholder={formData.state ? "Select your city" : "Select state first"}
          disabled={!formData.state}
          error={errors.city}
        />
      </div>

      {/* Pin Code */}
      <div>
        <SearchableDropdown
          label="Pin Code"
          value={formData.pinCode}
          options={pinCodes}
          onChange={handlePinChange}
          placeholder={formData.city ? "Select pin code" : "Select city first"}
          disabled={!formData.city}
          error={errors.pinCode}
        />
      </div>
    </div>
  );
};

export default LocationSelector;
